// Form runs: use the chosen dropdown values ('Random' falls through).
// Scheduled runs: no Style/Mode keys on the input -> fully random.
const STYLES = ['dylan-dog', 'enki-bilal', 'hugo-pratt', 'magnus', 'manga', 'milo-manara'];
const MODES = ['noir', 'fun', 'sensual'];
const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];
const inStyle = String($json.Style || '').toLowerCase();
const inMode = String($json.Mode || '').toLowerCase();
const style = STYLES.includes(inStyle) ? inStyle : pick(STYLES);
const mode = MODES.includes(inMode) ? inMode : pick(MODES);
return [{ json: { style, mode } }];

// Assemble all run config from the chosen style's Styles/<name>.md (read by
// the previous node, same source of truth as the Python CLI) and the chosen
// mode (noir | fun | sensual). Models/pacing are set at the bottom.
const md = $json.stdout;
const { style, mode } = $('Pick style & mode').first().json;

function allBlocks(text, heading) {
  const esc = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = text.match(new RegExp('^## ' + esc + '\\s*$', 'm'));
  if (!m) return [];
  const after = text.slice(m.index + m[0].length);
  const next = after.search(/^## /m);
  const section = next === -1 ? after : after.slice(0, next);
  return [...section.matchAll(/```[^\n]*\n([\s\S]*?)```/g)].map((x) => x[1].trim());
}
const firstBlock = (h) => allBlocks(md, h)[0] || '';

const imageSuffix = allBlocks(md, 'Image Prompt Suffix').join(' ');
if (!imageSuffix) throw new Error(`No Image Prompt Suffix found in Styles/${style}.md`);

const basePersona = firstBlock('Plot System Prompt') || 'You are a comic book director.';
const plotPersona =
  mode === 'fun' ? (firstBlock('Fun Plot System Prompt') || basePersona)
  : mode === 'sensual' ? (firstBlock('Sensual Plot System Prompt') || basePersona)
  : basePersona;

const sceneHint =
  mode === 'fun' ? ' Lean into visual comedy: exaggerated expressions, absurd props, comedic timing.'
  : mode === 'sensual' ? ' Lean into sensual tension: elegance, intimate atmosphere, charged body language — tasteful and suggestive, never explicit.'
  : '';
const scenePersona = (firstBlock('Scene System Prompt') || 'You are a comic book artist.') + sceneHint;

const ideaSystems = {
  noir: 'You invent premises for one-page horror/noir comics — gothic, melancholic, monsters as metaphors for grief and loss. Respond with exactly ONE original story premise as a single sentence. No quotes, no preamble, no explanation.',
  fun: 'You invent premises for one-page absurdist comedy comics — ridiculous situations, escalating chaos, genre tropes turned into punchlines. Respond with exactly ONE original story premise as a single sentence. No quotes, no preamble, no explanation.',
  sensual: 'You invent premises for one-page sensual romance comics — desire, longing, intimate tension between two people; tasteful and suggestive, never explicit. Respond with exactly ONE original story premise as a single sentence. No quotes, no preamble, no explanation.',
};

const plotStructure =
  '\nRespond ONLY with a single compact JSON object — no markdown fences, no explanation.\n' +
  'The JSON must have exactly these fields:\n' +
  '{"title": "short punchy story title", "tagline": "one sentence — the hook", "panel_count": <integer 4-12>, "beats": [{"index": 0, "beat": "one short sentence describing what happens in this scene"}, ...]}\n' +
  'beats must have exactly panel_count items, indexed 0 to panel_count-1. Each beat is ONE short sentence.';

const sceneStructure =
  '\nRespond ONLY with compact JSON, no markdown fences:\n' +
  '{"caption": "one short atmospheric narration sentence", "dialogue": "one short spoken line, or empty string if none", "image_prompt": "visual scene description under 50 words — focus on setting, lighting, character expression, and mood. Avoid explicit violence; convey tension atmospherically."}';

const musicMoods = {
  'dylan-dog': 'dark horror noir, slow suspenseful strings, ominous piano, cinematic dread',
  'hugo-pratt': 'mediterranean adventure jazz, nostalgic brass, old film score, melancholic',
  'magnus': 'dark thriller, pulsing low strings, noir detective atmosphere, brooding',
  'manga': 'anime action score, intense orchestral, dramatic taiko drums, energetic',
  'enki-bilal': 'sci-fi dystopia, cold electronic ambiance, eerie synthesizers, haunting',
  'milo-manara': 'romantic European cinema, sensual strings, Italian 70s film score, lush',
};
const moodMod =
  mode === 'fun' ? ', playful, whimsical, lighthearted'
  : mode === 'sensual' ? ', sultry, smooth, intimate'
  : '';
const musicMood = (musicMoods[style] || 'cinematic atmospheric, evocative, instrumental, dramatic') + moodMod;

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const runid = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

return [{ json: {
  runid,
  style,
  mode,
  dir: `/project/output/n8n/run-${runid}`,
  panelSeconds: 3,
  model: 'claude-sonnet-4-6',
  imageModel: 'fal-ai/bytedance/seedream/v4/text-to-image',
  imageSize: 'square_hd',
  musicModel: 'fal-ai/stable-audio-3/medium/text-to-audio',
  imageSuffix,
  ideaSystem: ideaSystems[mode] || ideaSystems.noir,
  plotSystem: plotPersona + plotStructure,
  sceneSystem: scenePersona + sceneStructure,
  musicMood,
} }];

// Accepts both response shapes: local OpenAI-compatible (choices[0].message.content)
// and Anthropic (content[0].text).
const j = $json;
const raw = (j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content)
  || (j.content && j.content[0] && j.content[0].text)
  || '';
const idea = raw.trim().replace(/^["']|["']$/g, '');
if (!idea) throw new Error('Model returned an empty idea');
return [{ json: { idea } }];

